import{_ as a,o as n,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Increased Attribution Coverage for TikTok for Business","description":"","frontmatter":{"title":"Increased Attribution Coverage for TikTok for Business","slug":"increased-attribution-coverage-for-tiktok-for-business"},"headers":[],"relativePath":"account-hub/increased-attribution-coverage-for-tiktok-for-business.md","filePath":"account-hub/increased-attribution-coverage-for-tiktok-for-business.md"}'),r={name:"account-hub/increased-attribution-coverage-for-tiktok-for-business.md"};function i(s,e,c,d,l,u){return n(),t("div",null,[...e[0]||(e[0]=[o('<p>Branch is strengthening our partnership with TikTok via TikTok&#39;s new Advanced Self Attributing Network (SAN) engine.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Starting November 25, 2024, the Branch and TikTok for Business integration will support an enhancement called <strong>Advanced SAN</strong>.</p><p>With Advanced SAN, Branch will send <strong>both</strong> ad link and SAN attribution decision results to TikTok, instead of just the latter. This new approach maximizes attribution coverage.</p><h2 id="enable-advanced-san" tabindex="-1">Enable Advanced SAN <a class="header-anchor" href="#enable-advanced-san" aria-label="Permalink to &quot;Enable Advanced SAN&quot;">​</a></h2><p>For some accounts, no change is needed to enable Advanced SAN. For these accounts, Advanced SAN could be auto-enabled because the correct TikTok app ID was provided in the account&#39;s Branch Dashboard prior to this transition.</p><p>If the value was missing or incorrect, then Advanced SAN could not be auto-enabled. In these cases, some light manual configuration is required to enable Advanced SAN.</p><h4 id="auto-enabled" tabindex="-1">Auto-Enabled <a class="header-anchor" href="#auto-enabled" aria-label="Permalink to &quot;Auto-Enabled&quot;">​</a></h4><p>If Advanced SAN is auto-enabled for your account, it means that TikTok has automatically backfilled your Branch Key in the TikTok Events Manager. Your Branch Key is required to ensure Advanced SAN support. We highly recommend verifying the Branch Key to ensure the correct one has been implemented.</p><p>Continue running your TikTok for Business campaigns using either the SAN integration or a Branch Ad Link.</p><h4 id="manual-configuration" tabindex="-1">Manual Configuration <a class="header-anchor" href="#manual-configuration" aria-label="Permalink to &quot;Manual Configuration&quot;">​</a></h4><p>If Advanced SAN has not been auto-enabled for your account, you can manually configure the set up.</p><h5 id="configuration-steps" tabindex="-1">Configuration Steps <a class="header-anchor" href="#configuration-steps" aria-label="Permalink to &quot;Configuration Steps&quot;">​</a></h5><p>To enable Advanced SAN:</p><ol><li><p>Visit your Branch Dashboard to ensure that the &quot;TikTok App ID&quot; field is filled out for your app(s):</p><ol><li><p>In the navigation panel, select <strong>Ads</strong>, then <strong>Partner Management</strong>.</p></li><li><p>Search for &quot;TikTok For Business SAN&quot; in the <strong>Ad Partners</strong> search bar and select the result.</p></li><li><p>In the <strong>Ad Account Information</strong> section, find your <strong>TikTok App IDs</strong>. If you don&#39;t have these IDs, you will need to <a href="./enable-tiktok-for-business.html#2-input-your-tiktok-app-id">generate them</a> first.</p><p>.png)</p></li></ol></li><li><p>Configure your Branch Key in the TikTok Events Manager:</p><ol><li><p>Visit the Account Settings <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">page</a> of your Branch Dashboard.</p></li><li><p>Copy the Branch Key listed there, which starts with <code>key_live_</code>.</p><p>.png)</p></li><li><p>Within the TikTok Events Manager, paste the Branch Key into the Partner Token field into the <strong>Edit Tracking</strong> module on the app details page.</p><p>.png)</p></li><li><p>Click &quot;Confirm&quot; to update the Branch Key.</p></li></ol></li></ol><h2 id="advanced-san-non-san" tabindex="-1">Advanced SAN + non-SAN <a class="header-anchor" href="#advanced-san-non-san" aria-label="Permalink to &quot;Advanced SAN + non-SAN&quot;">​</a></h2><p>Please note that beginning February 1, 2025, Branch will be <strong>discontinuing support</strong> for TikTok’s non-SAN module.</p><p>Branch recommends that customers enable Advanced SAN prior to the discontinuation of the non-SAN module.</p><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>To learn more about TikTok Advanced SAN, visit our <a href="./enable-tiktok-advanced-san.html">guide</a>.</p>',20)])])}const g=a(r,[["render",i]]);export{p as __pageData,g as default};
